   {
    "titre": "Bake",
    "detail": "Spread the goumeau cream over the risen dough and bake in a hot oven until the top is nicely golden."
   },
   {
    "titre": "Sugar at serving",
    "detail": "Immediately when removed from the oven, sprinkle generously with powdered sugar. Enjoy warm!"
   }
