 "fromagefraismaison": {
  "nom": "Homemade Fresh Cheese",
  "description": "Homemade fresh cheese paneer-style, ready in 15 minutes with no rennet needed: hot milk curdled with white vinegar, drained in cheesecloth. Spread it fresh, or press it firm to slice and pan-fry.",
  "etapes": [
   {
    "titre": "Heat the milk",
    "detail": "Bring the milk (UHT milk is fine here) to a gentle simmer: small bubbles forming around the edges, without a rolling boil."
   },
   {
    "titre": "Curdle with vinegar",
    "detail": "Off the heat, pour the vinegar in slowly while stirring: the milk will curdle (white curds + translucent whey). Add a splash more vinegar if it doesn't curdle enough."
   },
   {
    "titre": "Rest",
    "detail": "Let rest for 5 minutes so the curds come together."
   },
   {
    "titre": "Drain",
    "detail": "Pour into a strainer lined with clean cheesecloth. Rinse with cold water to remove the vinegar taste, then salt."
   },
   {
    "titre": "Press",
    "detail": "Squeeze the cheesecloth to remove the liquid. For a firm cheese you can slice and pan-fry: press under a weight for 30 minutes to 1 hour. For spreading: leave it softer."
   }
  ]
 },
 "mozzarellamaison": {
  "nom": "Homemade Mozzarella",
  "description": "True handmade stretched mozzarella: the milk curdles with lemon juice and rennet, then the curds are stretched while hot until they become supple and glossy. A thermometer is essential — and absolutely no ultra-pasteurized milk!",
  "etapes": [
   {
    "titre": "Acidify",
    "detail": "Pour the COLD milk (never ultra-pasteurized) into a large pot, add the lemon juice and stir well."
   },
   {
    "titre": "Heat to 32 °C",
    "detail": "Heat gently to 32 °C while stirring, then turn off the heat. KEY: a thermometer is essential."
   },
   {
    "titre": "Add Rennet",
    "detail": "Add the rennet diluted in a little non-chlorinated water, stir for 30 seconds, then don't touch it for 5 to 10 minutes: the curds will set (the surface will show clear cracks)."
   },
   {
    "titre": "Cut the Curds",
    "detail": "Cut the curds into 2 cm cubes. Heat gently again to 41-42 °C while stirring delicately: the curds separate from the whey."
   },
   {
    "titre": "Drain",
    "detail": "Scoop the curds with a slotted spoon into a colander, gently press to remove as much whey as possible."
   },
   {
    "titre": "Stretch",
    "detail": "Plunge the curds in portions into water heated to 80-85 °C until they become supple and elastic (~60 °C at the center). Gloves recommended, it's hot!"
   },
   {
    "titre": "Stretch and Shape",
    "detail": "Stretch and fold the curd mass several times until it is smooth and glossy. Salt, then form into balls."
   },
   {
    "titre": "Chill and Store",
    "detail": "Plunge the balls into ice water for 10-15 minutes. Store in the refrigerator in a little salted whey. Best enjoyed within 2-3 days."
   }
  ]
 },
