 "matchalattewi": {
  "nom": "Matcha Latte",
  "description": "Matcha Latte — a creamy and energizing Japanese beverage. Ceremonial matcha powder whisked with hot milk, lightly sweetened with honey or syrup. Antioxidants and zen attitude!",
  "etapes": [
   {
    "titre": "Choose your matcha",
    "detail": "CRITICAL: use REAL ceremonial-grade matcha (high quality, vibrant green). Culinary matcha (yellowish-green) is bitter. Recommended brands: Ippodo, Marukyu Koyamaen."
   },
   {
    "titre": "Water at the right temperature",
    "detail": "Heat water to 70-75°C (NOT boiling — or the matcha will taste bitter). CHEF'S TIP: bring to a boil then let it sit for 2 minutes to cool to the proper temperature."
   },
   {
    "titre": "Sift the matcha",
    "detail": "THE MATCHA SECRET: pass the matcha through a fine mesh sieve to avoid lumps. This is WHAT ALL matcha sommeliers do."
   },
   {
    "titre": "Prepare the base",
    "detail": "In a large bowl (Japanese chawan or wide bowl): pour 1 tsp of sifted matcha + 60ml hot water."
   },
   {
    "titre": "Whisk with the chasen",
    "detail": "TRADITIONAL TECHNIQUE: whisk with a CHASEN (bamboo whisk) in quick ZIG-ZAG motions (W or M) for 30 seconds. The matcha should become FOAMY on the surface. If you don't have one: use an electric whisk."
   },
   {
    "titre": "Heat the milk",
    "detail": "Meanwhile, heat 200ml of milk (cow's or oat for a modern version) to 65°C. DO NOT BOIL. Optional: froth with a milk frother."
   },
   {
    "titre": "Sweeten (optional)",
    "detail": "In the foamy matcha, add: 1 tbsp maple syrup, honey or agave + 1/2 tsp vanilla. Stir."
   },
   {
    "titre": "Assemble",
    "detail": "Pour the hot milk SLOWLY in a thin stream over the matcha foam. If done right: the pure green matcha stays on top, the white milk below = signature visual effect."
   },
   {
    "titre": "Zen service",
    "detail": "Serve IMMEDIATELY in a large cup. Dust a little matcha on the surface. For ICED version: pour over ice cubes. For original version: no sugar, just matcha + milk. 抹茶ラテ!"
   }
  ]
 },
 "mangolassi": {
  "nom": "Mango Lassi",
  "description": "Mango Lassi — a creamy Indian beverage made with mango and yogurt. Silky, refreshing, and naturally sweet. The perfect accompaniment to spicy curry or served as dessert.",
  "etapes": [
   {
    "titre": "Choose the mangoes",
    "detail": "ESSENTIAL: RIPE mangoes (yield to finger pressure, fragrant). Alphonso (India) or Kent varieties ideal. CHEF'S TIP: for a quick version, use canned MANGO PUREE from India (Ratna, Patak's)."
   },
   {
    "titre": "Prepare the mango",
    "detail": "Peel the mango, cut the flesh around the central pit. Cut into cubes. If too firm: let sit 1 hour at room temperature."
   },
   {
    "titre": "Cardamom (authentic option)",
    "detail": "SECRET OF INDIAN LASSI: open 4 green cardamom pods. Retrieve the black seeds. Crush in a mortar or crush with the back of a spoon. This is THE signature flavor."
   },
   {
    "titre": "Well-chilled yogurt",
    "detail": "Use PLAIN WHOLE MILK YOGURT (Greek yogurt or Indian Dahi yogurt). Well-chilled = maximum creaminess. DO NOT use 0% (watery texture)."
   },
   {
    "titre": "Blend",
    "detail": "In a blender: mango cubes (400g) + yogurt (400ml) + milk (200ml) + sugar (2 tbsp adjust based on mango sweetness) + ground cardamom + 1 handful of ice cubes. Blend 30-45 seconds at full power."
   },
   {
    "titre": "Texture",
    "detail": "Should be SILKY and CREAMY like a milkshake. If too thick: add milk. If too thin: add ice or yogurt."
   },
   {
    "titre": "Serving",
    "detail": "Serve in CHILLED glasses (in freezer 10 minutes before). Sprinkle a pinch of ground cardamom or crushed pistachios on top."
   },
   {
    "titre": "Final touches",
    "detail": "A fresh mint leaf, a lime zest. Serve with a straw. PERFECT with spicy curry (cools the palate) or alone as a snack."
   }
  ]
 },
